import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axiosInstance from '../api/axiosConfig';

const AdminDashboard = () => {
  const [stats, setStats] = useState({ totalStudents: 0, totalCourses: 0, totalEnrolments: 0 });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    setLoading(true);
    setError('');
    try {
      const response = await axiosInstance.get('/api/admin/dashboard');
      setStats(response.data);
    } catch (err) {
      console.error(err);
      setError('Failed to fetch dashboard metrics. Please reload the page.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container py-5 text-light">
      <div className="mb-5">
        <h2 className="fw-bold bg-gradient-primary-to-secondary text-transparent bg-clip-text d-inline-block">
          Admin Dashboard
        </h2>
        <p className="text-muted mb-0">Overview of the system's active courses, registered students, and enrolments</p>
      </div>

      {error && (
        <div className="alert alert-danger border-0 bg-danger bg-opacity-10 text-danger rounded-3 mb-4 shadow-sm" role="alert">
          {error}
        </div>
      )}

      {loading ? (
        <div className="d-flex flex-column align-items-center justify-content-center py-5">
          <div className="spinner-border text-primary mb-3" role="status">
            <span className="visually-hidden">Loading...</span>
          </div>
          <span className="text-muted">Loading metrics...</span>
        </div>
      ) : (
        <>
          {/* Stats Cards */}
          <div className="row g-4 mb-5">
            {/* Students Stats Card */}
            <div className="col-12 col-md-4">
              <div className="card border-0 bg-slate-800 text-light shadow-sm rounded-4 overflow-hidden position-relative">
                <div className="card-body p-4">
                  <div className="d-flex align-items-center justify-content-between mb-3">
                    <span className="text-muted small fw-semibold text-uppercase">Total Students</span>
                    <span className="fs-3 bg-primary bg-opacity-10 text-primary p-2 rounded-3">
                      👥
                    </span>
                  </div>
                  <h2 className="fw-extrabold text-white mb-2">{stats.totalStudents}</h2>
                  <Link to="/manage-students" className="text-primary text-decoration-none small fw-medium d-flex align-items-center gap-1">
                    View Student List <span>→</span>
                  </Link>
                </div>
              </div>
            </div>

            {/* Courses Stats Card */}
            <div className="col-12 col-md-4">
              <div className="card border-0 bg-slate-800 text-light shadow-sm rounded-4 overflow-hidden position-relative">
                <div className="card-body p-4">
                  <div className="d-flex align-items-center justify-content-between mb-3">
                    <span className="text-muted small fw-semibold text-uppercase">Total Courses</span>
                    <span className="fs-3 bg-success bg-opacity-10 text-success p-2 rounded-3">
                      📚
                    </span>
                  </div>
                  <h2 className="fw-extrabold text-white mb-2">{stats.totalCourses}</h2>
                  <Link to="/manage-courses" className="text-success text-decoration-none small fw-medium d-flex align-items-center gap-1">
                    Manage Course Offerings <span>→</span>
                  </Link>
                </div>
              </div>
            </div>

            {/* Enrolments Stats Card */}
            <div className="col-12 col-md-4">
              <div className="card border-0 bg-slate-800 text-light shadow-sm rounded-4 overflow-hidden position-relative">
                <div className="card-body p-4">
                  <div className="d-flex align-items-center justify-content-between mb-3">
                    <span className="text-muted small fw-semibold text-uppercase">Total Enrolments</span>
                    <span className="fs-3 bg-info bg-opacity-10 text-info p-2 rounded-3">
                      📝
                    </span>
                  </div>
                  <h2 className="fw-extrabold text-white mb-2">{stats.totalEnrolments}</h2>
                  <span className="text-muted small">
                    Active student-course links
                  </span>
                </div>
              </div>
            </div>
          </div>

          {/* Quick Actions Panel */}
          <div className="card border-0 bg-slate-800 shadow-sm rounded-4 overflow-hidden">
            <div className="card-body p-4">
              <h5 className="fw-bold mb-4">Quick Administrative Tools</h5>
              <div className="row g-3">
                <div className="col-12 col-sm-6">
                  <div className="p-3 bg-slate-900 rounded-3 h-100 d-flex flex-column justify-content-between">
                    <div>
                      <h6 className="fw-semibold text-white">Course Management Portal</h6>
                      <p className="text-muted small mb-3">Add new courses, update class curriculum or duration, or remove outdated courses from the catalog.</p>
                    </div>
                    <Link to="/manage-courses" className="btn btn-primary btn-sm py-2 rounded-2 fw-semibold w-fit">
                      Go to Courses
                    </Link>
                  </div>
                </div>
                <div className="col-12 col-sm-6">
                  <div className="p-3 bg-slate-900 rounded-3 h-100 d-flex flex-column justify-content-between">
                    <div>
                      <h6 className="fw-semibold text-white">Student Enrollment Tracking</h6>
                      <p className="text-muted small mb-3">View profiles, registration dates, and inspect which specific courses each student is enrolled in.</p>
                    </div>
                    <Link to="/manage-students" className="btn btn-outline-primary btn-sm py-2 rounded-2 fw-semibold w-fit text-light border-opacity-50">
                      Go to Students
                    </Link>
                  </div>
                </div>
              </div>
            </div>
          </div>
        </>
      )}
    </div>
  );
};

export default AdminDashboard;
